var b="url",c="打样任务创建_待提交_.html",d="generationDate",e=new Date(1781589181328.4),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="OnLoadVariable",r="Water",s="PreVerStatus",t="page",u="packageId",v="633815b46a3242caa52e9417521373b9",w="type",x="Axure:Page",y="打样任务创建(待提交)",z="notes",A="annotations",B="style",C="baseStyle",D="627587b6038d43cca051c114ac41ad32",E="pageAlignment",F="center",G="fill",H="fillType",I="solid",J="color",K=0xFFFFFFFF,L="image",M="imageAlignment",N="near",O="imageRepeat",P="auto",Q="favicon",R="sketchFactor",S="0",T="colorStyle",U="appliedColor",V="fontName",W="Applied Font",X="borderWidth",Y="borderVisibility",Z="borderFill",ba=0xFF797979,bb="cornerRadius",bc="cornerVisibility",bd="outerShadow",be="on",bf=false,bg="offsetX",bh=5,bi="offsetY",bj="blurRadius",bk="spread",bl="r",bm=0,bn="g",bo="b",bp="a",bq=0.349019607843137,br="adaptiveStyles",bs="interactionMap",bt="diagram",bu="objects",bv="id",bw="2ebc04fd5dba44a5b2e617148e0097d9",bx="label",by="friendlyType",bz="样衣信息",bA="referenceDiagramObject",bB="styleType",bC="visible",bD=true,bE=2410,bF=388,bG="imageOverrides",bH="masterId",bI="545113ff5f0a4d579cb98695d5b6ca61",bJ="6a7e564bcc724d2886dc36a98394d0dc",bK="热区",bL="imageMapRegion",bM=100,bN=45,bO="location",bP="x",bQ="y",bR=1454,bS="fef12657096b49468ade66afab885358",bT="矩形",bU="vectorShape",bV=476,bW=368,bX="31e8887730cc439f871dc77ac74c53b6",bY=1784,bZ="generateCompound",ca="4454918a0cfb40168bf4719c8dcfbd81",cb="4988d43d80b44008a4a415096f1632af",cc=821,cd=195,ce=20,cf=465,cg="7082b18eae0a4ab5b7a7a33117c6a5af",ch="foreGroundFill",ci=0xFFD9001B,cj="opacity",ck=1,cl=193,cm=15,cn=430,co="onClick",cp="eventType",cq="Click时",cr="description",cs="点击或轻触",ct="cases",cu="conditionString",cv="isNewIfGroup",cw="caseColorHex",cx="AB68FF",cy="actions",cz="action",cA="linkWindow",cB="在 当前窗口 打开 读写/只读样式",cC="displayName",cD="打开链接",cE="actionInfoDescriptions",cF="读写/只读样式",cG="target",cH="targetType",cI="读写_只读样式.html",cJ="includeVariables",cK="linkType",cL="current",cM="tabbable",cN="masters",cO="545113ff5f0a4d579cb98695d5b6ca61",cP="Axure:Master",cQ="fn",cR="1",cS="ownerId",cT="5b3d559501d045f38a74690a19dd948f",cU="提交",cV="说明",cW="<p><span>1.任务流的提交</span></p><p><span>2.提交时判断</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#0000FF;\">读写</span><span>权限页签的“未提交”版本与上一个已提交版本</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">是否存在差异</span></p><p><span>&nbsp;&nbsp; &nbsp; a.存在差异：以当前数据生成新版本</span></p><p><span>&nbsp;&nbsp; &nbsp; b.不存在差异：不生成新版本</span></p>",cX="2",cY="295c11605669453fa61b5cb2fd297ce2",cZ="导出",da="<p><span>1.导出文件</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.格式：word</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.名称：打样单号_款号_工艺单.docx</span></p><p><span>2.固定页眉：标题</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.'配置项特定'+工艺单</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.使用配置项system_config_COMPANY_NAME</span></p><p><span>3.固定页眉：款式信息</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.展示对应款基础信息</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.包含字段：单号、客户、导出日期、款号、款名、内部款号、款式图片</span></p><p><span>4.制样清单：取[基础数据]中的</span><span style=\"text-decoration:underline ;\">打样清单</span></p><p><span>5.尺码表：取[尺寸表]中的</span><span style=\"text-decoration:underline ;\">尺码清单</span></p><p><span>6.工序表：取[工序工价]中的</span><span style=\"text-decoration:underline ;\">工序表</span></p><p><span>7.工艺要求：取[工艺要求]中各工段及包装要求中</span><span style=\"text-decoration:underline ;\">“富文本”的数据</span></p><p><span>8.BOM清单：取[物料信息]中的</span><span style=\"text-decoration:underline ;\">建档物料</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.根据系统配置项system_config_BOM_FORMAT取Bom3或BOM4的数据</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.排序要求</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b1.优先物料类型排序①面料②辅料</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b2.其次同一类型下，按照计算出来的“计划用量”从大到下顺序</span></p>",db="3",dc="2fa4b7bf80d448059637a5418a1fe639",dd="生产分配",de="<p><span>1.校验当前打样订单的是否存在[工序工价]的版本</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.不存在：Toast提示“暂无工序版本，无法进行分配”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.存在：通过校验</span></p><p><span>2.校验当前打样订单的[样衣吊牌]下是否存在版本</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.不存在：Toast提示“暂未生成吊牌，无法进行分配”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.存在：通过校验</span></p><p><span>3.通过校验：弹窗填写分配信息</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.到达任务由“报工方式”决定</span></p>",df="4",dg="b2d70bb193f34292b52cce6cf60825ea",dh="采购需求",di="<p><span>按钮展示权限</span></p><p><span>1.在任务页面[物料信息]权限为 只读/读写 时展示</span></p><p><span>2.在任务页面[物料信息]权限为 隐藏 时不展示</span></p><p><span><br></span></p><p><span>按钮校验</span></p><p><span>1.校验当前打样订单的是否存在[物料明细]的版本，不存在时Toast提示：暂无BOM版本，无法发起采购</span></p>",dj="5",dk="0240fac79bae423495b5f89c45670bcd",dl="归档版本：3",dm="<p><span>在[款式归档操作]中查询该&quot;款号&quot;的归档版本+1</span></p>",dn="6",dp="6723ae1177cd47a58035df2920adb2c1",dq="确认",dr="<p><span>1.“归档说明”的必填校验；否则提示：请填写归档说明</span></p><p><span>2.按照实际该“款号”的归档版本进行递增</span></p><p><span>3.新增一条待提交的任务至[款式归档操作]</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.归档版本号：'V'+'递增数字'+'-'+'款号'，例如V2-kuanhao001</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.取当前打样订单的版单类型，作为款式归档操作的“归档类型”</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; c.取当前打样订单(DYDD)，作为款式归档操作的“关联单号”</span></p><p><span>4.Toast：已生成，可在 [ 款式归档操作 ] 中查看</span></p><p><span>5.款式归档数据</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.颜色/尺码：取当前版单的打样颜色、打样尺码作为归档颜色、归档尺码</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.总体安排、补充资料、尺寸表、版型文件、物料明细、工艺要求、工序工价、码比方案、成本核价、个订物料：均取当前版单</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#3399FF;\">最新已提交</span><span>的版本数据</span></p>",ds="7",dt="8120b8add8bd49bc8f22df035f45d804",du="* BOM版本：",dv="<p><span>1.数据源：当前打样单的[物料明细]的版本</span></p><p><span>2.默认值：最新的一版[物料明细]</span></p><p><span>3.每次切换“Bom版本”时，重新查询对应“已生成次数”</span></p>",dw="8",dx="4e832684137a4ff099cb9fe31abfb88f",dy="已生成次数：",dz="<p><span>跟随&quot;BOM版本&quot;发起过的样衣物料需求 ( [</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#0F0F0F;\">物料采购系统：物料需求(新) </span><span>] ) ，每次切换“Bom版本”时，重新查询</span></p>",dA="9",dB="3d1a68eaa2724ad58e1942481e05c191",dC="全部物料",dD="<p><span>1.默认不勾选</span></p><p><span>2.不勾选：用于列表</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">过滤掉“历史下发需求”≥“需求数量”</span><span>的行</span></p><p><span>3.右侧Tooltips提示字：未勾选时仅展示'需求数量'＞'历史下发需求'的物料</span></p>",dE="10",dF="2b138780d6614643b95bf978751576d5",dG="(单元格)",dH="<p><span>1.每切换“BOM版本”时重新拉取清单</span></p><p><span>2.默认是否勾选(跟随&quot;已生成次数&quot;)</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.已生成次数==0：默认全选</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.已生成次数 ≥ 1：默认不选</span></p><p><span>3.清单展示</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.排除“来源==客供”的数据行后对BOM进行MRP计算</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.以BOM中的SKU去重展示</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b1.需求数量：根据</span><span style=\"color:#0F0F0F;\">SKU对应的 Σ成衣颜色[Σ(成衣件数*单耗)] 进行计算</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b2.历史下发需求：在[</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#0F0F0F;\">物料采购系统：物料需求(新) </span><span>]中满足以下全部条件的数据行的“当前需求数量”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; ①状态为'未采购'或'已采购'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; ②“订单”与当前'打样订单号'一致</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; ③SKU与当前行一致</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; c.SKU行数过多时不要分页，固定高度，下滑展示全部</span></p>",dI="11",dJ="8fa65baac3c940d68580db45ad60c762",dK="要求寄样",dL="<p><span>1.默认是否选中：由对应BOM版本中获取</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; a.该SKU有多行时，全部行均未选中时，默认为'未选中'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; b.该SKU有多行时，任意行选中时，默认为'选中'</span></p>",dM="12",dN="bcc2e9b0f09f43e88ea30fa55b6dfa8b",dO="Sub Header",dP="<p><span>1.默认选中：全数下发</span></p>",dQ="13",dR="82122e0a33f949e88e599856f3939c48",dS="关闭对应已下发的物料需求",dT="<p><span>1.仅“下发方式==全数下发”时展示该复选框</span></p><p><span>2.默认勾选</span></p><p><span>3.勾选应用：确认生成后将[</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#0F0F0F;\">物料采购系统：物料需求(新) </span><span>]中'勾选行SKU-当前打样单号'一致行进行处理</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.“未采购”状态-&gt;置为'已关闭'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.“已采购[x]”状态-&gt;置为'已关闭[x]'</span></p>",dU="14",dV="72627bdc118343339e1b087595f0b9dd",dW="确认生成",dX="<p><span style=\"color:#0F0F0F;\">1.校验BOM版本非空，否则Toast提示：请选择BOM版本</span></p><p><span style=\"color:#0F0F0F;\">2.校验是否存在勾选，否则Toast提示：请勾选要下发的采购需求</span></p><p><span style=\"color:#0F0F0F;\">3.</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">按勾选</span><span style=\"color:#0F0F0F;\">的SKU行生成一条记录至</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#0F0F0F;\"> [ 物料采购系统：物料需求(新) ]</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; a.订单交期、BOM版本：均以当前下发时的为准</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; b.生产需求数量：取勾选行对应的“需求数量”</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; c.当前需求数量：根据选中的'下发方式'确认数值</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; c1.全数下发：取勾选行对应的“需求数量”</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; c2.补充下发：取勾选行对应的“需求数量-</span><span>历史下发需求</span><span style=\"color:#0F0F0F;\">” (计算数值小于等于0的行进行忽略，</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#0F0F0F;\">不生成行</span><span style=\"color:#0F0F0F;\">)</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; d.</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#0F0F0F;\">将SKU对应的一或多个供应商/未税单价/税率/含税单价中查出来的一组作为SKU的 “供应商”、“未税单价”、“税率”、“含税单价”</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; e.</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#0F0F0F;\">单行初始化状态为“未采购”</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#0F0F0F;\">4.</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">勾选</span><span style=\"color:#0F0F0F;\">的SKU行若对应的</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">“要求寄样”为选中</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#0F0F0F;\">，校验</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#F59A23;\">当前订单号(DYDD)+对应行的SKU</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#0F0F0F;\">是否存在于</span><span>[</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#0F0F0F;\">物料采购系统：寄样记录 </span><span>] 的 </span><span style=\"text-decoration:underline ;\">寄样汇总</span><span> 下</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; a.存在：不做处理</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; b.不存在：在</span><span>[</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#0F0F0F;\">物料采购系统：寄样记录 </span><span>] 的 </span><span style=\"text-decoration:underline ;\">寄样汇总</span><span> 下新增对应记录行</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b1.状态：进行中</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b2.订单号、自定义单号、客户、业务员、款号、款名：取当前打样单上的信息</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b3.物料编码、物料名称、规格/门幅(克重)、颜色：取勾选行对应的SKU信息</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b4.其它字段为空</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#0F0F0F;\">5.若</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;color:#02A7F0;\">选中</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#0F0F0F;\">“关闭对应已下发物料需求”项</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; a.在</span><span>[</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#0F0F0F;\">物料采购系统：物料需求(新) </span><span>]中找到满足以下条件的行</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; a1.“SKU”与本次第3点中生成的一致</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; a2.“订单”与当前打样单一致</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.将找到行的状态</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;\">置为'已关闭'</span><span style=\"color:#0F0F0F;\">，[数值]与采购单一致，为'0'时不展示</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b1.</span><span>“未采购” -&gt; '已关闭'</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b2.</span><span>“已采购[x]” -&gt; '已关闭[x]'</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#0F0F0F;\">6.当前BOM版本对应的已生成次数+1</span></p>",dY="15",dZ="6b25c1a1b05a4b02ac5f48883e6a7125",ea="* 工序版本",eb="<p><span>1.数据源：当前打样单的[工序工价]的版本</span></p><p><span>2.默认值：最新的一版[工序工价]</span></p>",ec="16",ed="c043a1bf0f3f46f09021c1029f628355",ee="* 报工方式",ef="<p><span>1.默认值：整件报工</span></p><p><span>2.数据源</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.固定选项：整件报工</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.其他选项：选中的“工序版本”内包含的[工段名称]</span></p><p><span>2.数据源根据选中的“工序版本”变更</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.每切换“工序版本”，将“报工方式”切换为“整件报工”</span></p>",eg="17",eh="9ba6d2b6bfd147aca13f0cbc0c22f24c",ei="* 样衣版本",ej="<p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">1.进入弹窗时，默认最新的版本</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">2.每切换样衣版本，须要重新获取样衣版本下对应的样衣吊牌</span></p>",ek="18",el="7878e740be714384a90d57632173bd1c",em="批量分配",en="<p><span>1.支持模糊搜索“账号”和“用户名”</span></p><p><span>2.每次选中后，将选中的值覆盖至清单的“分配人”列</span></p>",eo="19",ep="c27b0cee59024b278b98be0bf712625d",eq="吊牌",er="<p><span>1.根据选中的“样衣版本”展示对应的吊牌</span></p><p><span>2.全部展示，无须分页</span></p>",es="20",et="89c19c780ef348e7b38a335bac5e07df",eu="* 分配人",ev="<p><span>1.支持模糊搜索“账号”和“用户名”</span></p><p><span>2.可由选中的“批量分配”覆盖整列值</span></p>",ew="21",ex="1016787ddcea457d8abc3addd547ef92",ey="确认分配",ez="<p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">1.校验工序版本、报工方式、样衣版本、完成时间是否存在为空，否则Toast提示：请选择XXX</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">2.校验清单中的“分配人”是否存在为空，否则Toast提示：请选择分配人</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">3.按照有几个“分配人”分别生成报工方式对应的任务</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; a.按“报工方式”生成任务位置</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; i.整件报工：[研发管理系统&gt;&gt;样衣工序提交]</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; ii.裁剪：[研发管理系统&gt;&gt;样衣裁剪操作]</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; iii.面料加工：[研发管理系统&gt;&gt;样衣面料操作]</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; iv.缝制：[研发管理系统&gt;&gt;样衣缝制操作]</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; v.裁片加工：[研发管理系统&gt;&gt;样衣裁片加工]</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; vi.前道：[研发管理系统&gt;&gt;样衣前道操作]</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; vii.中道：[研发管理系统&gt;&gt;样衣中道操作]</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; viii.后道：[研发管理系统&gt;&gt;样衣后道操作]</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; ix.洗水：[研发管理系统&gt;&gt;样衣洗水操作]</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; b.将相同分配人的吊牌生成一个任务</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; i.分配人作为对应“任务人”</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; ii.完成时间作为对应“要求完成时间”</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; iii.样衣数量：相同分配人进入任务的吊牌件数</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; iv.提交类型：均为“分配吊牌”(因为都固定是某个吊牌版本下的样衣)</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">4.记录当前生成任务的taskID</span></p>",eA="22",eB="8caf59617506437d874bf69dc2b8910a",eC="重置打样",eD="<p><span>按钮展示权限：仅在[打样任务创建]任务下，且任务状态为'已完成'的详情页展示该按钮</span></p>",eE="23",eF="b1293b55931741a19348f6ad8b855acf",eG="添加",eH="<p><span>仅</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">非空</span><span>且</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">非重复尺码</span><span>时添加至</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;text-decoration:underline ;\">设置尺寸</span><span>尾部</span></p>",eI="24",eJ="99907b3baa9b4ca3bed6b4a058fd83b5",eK="设置尺码：",eL="<p><span>1.初始化：打开弹窗前打样单的 [ 制样清单 ] 的成衣尺码</span></p><p><span>2.由</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;text-decoration:underline ;\">新增尺码</span><span>的【添加】生效后添加尺码至尾部</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; a.同时将 [ 制样清单 ] 新增对应列</span></p><p><span>3.在当前移除尺码</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; a.将 [ 制样清单 ] 中的对应列进行移除</span></p>",eM="25",eN="9eab9e1a4f5e417693e7ca9ab42c1c7c",eO="颜色/尺码",eP="<p><span>1.初始化：打开弹窗前打样单的 [ 制样清单 ] 的成衣颜色-成衣尺码</span></p><p><span>2.成衣尺码：顶部行</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; a.表头数据：跟随顶部的</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;text-decoration:underline ;\">设置尺码</span></p><p><span>3.成衣颜色：左侧列</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; a.按行下拉选中</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; b.数据源：[基础数据系统&gt;&gt;款式管理：成衣颜色]</span></p>",eQ="26",eR="619aca1597b246c1a903e75e0d85e1d7",eS="原单据任务取消 (存在后置业务单据时不生",eT="<p><span>默认选中</span></p>",eU="27",eV="15840f244aad45418e72115120f6622e",eW="<p><span style=\"color:#0F0F0F;\">1.校验</span><span style=\"text-decoration:underline ;color:#0F0F0F;\">设置尺码</span><span style=\"color:#0F0F0F;\">非空，否则Toast提示：请设置成衣尺码</span></p><p><span style=\"color:#0F0F0F;\">2.校验</span><span style=\"text-decoration:underline ;color:#0F0F0F;\">成衣颜色列</span><span style=\"color:#0F0F0F;\">非空，否则Toast提示：请选择成衣颜色</span></p><p><span style=\"color:#0F0F0F;\">3.校验 [ 制样清单 ] 的总数大于0，否则Toast提示：请填写打样数量</span></p><p><span style=\"color:#0F0F0F;\">4.通过全部校验</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; a.</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">新增打样单(DYDD)</span><span>：</span><span style=\"color:#0F0F0F;\">打样单号按新建逻辑自动生成</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; a1.</span><span style=\"color:#4B7902;\">基础信息</span><span style=\"color:#0F0F0F;\">：[制样清单] 以当前弹窗为准，其它数据均与原单据一致</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; a2.</span><span style=\"color:#4B7902;\">总体安排、补充资料、版型文件、工艺要求、工序工价、码比方案</span><span style=\"color:#0F0F0F;\">：均按原单据的最新数据</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">直接覆盖</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; a3.</span><span style=\"color:#4B7902;\">尺寸表</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a3_1.部位、CODE、量衣说明、尺寸单位、档差、公差、备注：直接覆盖</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a3_2.</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;\">尺码列数据</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">：将当前归档尺码和引用数据项中尺码进行匹配(当前归档尺码无法被匹配的列，填充为'0')</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; a4.</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#4B7902;\">物料明细(建档物料</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">BOM3</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#4B7902;\">)</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a4_1.各成衣颜色清单</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; </span><span style=\"color:#0F0F0F;\">&nbsp; &nbsp; &nbsp;&nbsp; </span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">①能够匹配到成衣颜色的拉取</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;text-decoration:underline ;\">对应成衣颜色</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">的清单</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; </span><span style=\"color:#0F0F0F;\">&nbsp; &nbsp; &nbsp;&nbsp; </span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">②无法被匹配的成衣颜色拉取引用单据中</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;text-decoration:underline ;\">第一个成衣颜色</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">的清单</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a4_2.单个成衣颜色清单中&quot;成衣尺码(规格/单耗)&quot;</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; </span><span style=\"color:#0F0F0F;\">&nbsp; &nbsp; &nbsp;&nbsp; </span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">①能够匹配到成衣尺码的拉取</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;text-decoration:underline ;\">对应成衣尺码应用</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">的规格和单耗</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; </span><span style=\"color:#0F0F0F;\">&nbsp; &nbsp; &nbsp;&nbsp; </span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">②无法被匹配的成衣尺码的拉取引用单据中</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;text-decoration:underline ;\">第一个成衣尺码应用</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">的规格和单耗</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; a5.</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">物料明细(建档物料</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;\">BOM4</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">)：暂不处理</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; a6.</span><span style=\"color:#4B7902;\">打样吊牌</span><span style=\"color:#0F0F0F;\">：</span><span>按新</span><span style=\"color:#0F0F0F;\">[制样清单]</span><span>生成第一版样衣吊牌</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a6_1.</span><span>生成时间、生成人：当前创建时间及操作人</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a6_2.</span><span>版本说明版本说明：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">默认生成</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; a7.</span><span style=\"color:#D9001B;\">任务描述</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a7_1.任务到达</span><span>：打样任务创建</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a7_2.任务状态：待提交</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a7_3.任务执行人</span><span>：当前操作人</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; b.若</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#C2761C;\">原单据任务取消==选中</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b1.校验原单据的'入库任务'状态</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b1_1.入库任务==已生成：跳出校验</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b1_2.入库任务==未生成：继续执行校验</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b2.校验原单据的'生产分配'数量</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b2_1.生产分配 ! = 0：跳出校验</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b2_2.生产分配 == 0：继续执行校验</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b3.校验原单据的当前任务无后置任务</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b3_1.</span><span style=\"color:#0F0F0F;\">后置任务</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\"> ! = 0：跳出校验</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b3_2.</span><span style=\"color:#0F0F0F;\">后置任务</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\"> == 0：继续执行校验</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b4.全部校验通过</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b4_1.将当前任务的状态置为'已取消'</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; c.页面跳转：跳转至新建的打样单的详情页</span></p><p><span style=\"color:#0F0F0F;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; c1.进入路径：由[打样任务创建]的</span><span style=\"text-decoration:underline ;color:#0F0F0F;\">待提交</span><span style=\"color:#0F0F0F;\">页签进入</span></p>",eX="28",eY="6d31b9a13d8a44d5a83687fc68164353",eZ="保存",fa="<p><span>1.尺码不能为空</span></p><p><span>2.重复尺码自动忽略</span></p>",fb="d6fbba94cb5e4edb81b1b1166058a9bf",fc="标题-1445",fd=1445,fe=119,ff="6f654cc4086e4571aaba6dbd0ec92bfa",fg="358766962233424c84b2d4d801ebef60",fh="'Nunito Sans', sans-serif",fi=300,fj=110,fk=1462,fl=72,fm="fontSize",fn="14px",fo="03e634a84525452fa3e3b6d3add1abd4",fp="权限管理",fq=0xFF1E1E1E,fr=1425,fs=30,ft="adb1a483fc0a441ab5ca24c062ba055a",fu="stateStyles",fv="mouseOver",fw="selected",fx="verticalAlignment",fy="middle",fz=0xFF367EA9,fA=0xFFD3DDE9,fB=118,fC="c15b6caa576d4deea69dfba9762996c2",fD=240,fE="c24b14186ab54b5e8b47eccbf4300dbd",fF=0xFFFFFF,fG=148,fH="d9d5b18aa05c483ba1e4810eb3987364",fI=520,fJ=220,fK=28,fL=155,fM=0x555555,fN="f80ffd6f153946bc8de9e7864552ded6",fO=250,fP=852,fQ=158,fR=0x797979,fS="442f94cfc65142139bb0ae285de56bf4",fT="图片",fU="imageBox",fV=144,fW=145,fX="75a91ee5b9d042cfa01b8d565fe289c0",fY=909,fZ=189,ga="images",gb="u550~normal~",gc="images/打样任务创建_待提交_/u550.png"